import faiss
import numpy as np

DIM = 768  # ViT-L-14

class UnifiedCLIPIndex:
    def __init__(self):
        self.index = faiss.IndexFlatIP(DIM)
        self.records: list[dict] = []

    def add_image(self, path: str):
        vec = embed_image(path).astype(np.float32).reshape(1, -1)
        self.index.add(vec)
        self.records.append({"type": "image", "path": path})

    def add_text(self, text: str, metadata: dict | None = None):
        vec = embed_text(text).astype(np.float32).reshape(1, -1)
        self.index.add(vec)
        self.records.append({"type": "text", "text": text, **(metadata or {})})

    def search(self, query: str | np.ndarray, k: int = 5) -> list[dict]:
        if isinstance(query, str):
            q_vec = embed_text(query).astype(np.float32).reshape(1, -1)
        else:
            q_vec = query.astype(np.float32).reshape(1, -1)
        scores, ids = self.index.search(q_vec, k)
        return [
            {"score": float(scores[0][j]), **self.records[ids[0][j]]}
            for j in range(k)
            if ids[0][j] != -1
        ]

