from langchain_openai import ChatOpenAI
from langchain_core.messages import HumanMessage
import base64

reranker = ChatOpenAI(model="gpt-4o-mini", temperature=0)

def score_image_relevance(query: str, image_path: str) -> float:
    """Return 0.0-1.0 relevance score from a vision LLM."""
    with open(image_path, "rb") as f:
        b64 = base64.b64encode(f.read()).decode()
    resp = reranker.invoke([
        HumanMessage(content=[
            {"type": "text", "text": (
                f"Query: {query}\n\n"
                "Rate how relevant this image is to the query on a scale of 0 to 10."
                " Reply with only the number."
            )},
            {"type": "image_url", "image_url": {"url": f"data:image/png;base64,{b64}"}},
        ])
    ])
    try:
        return float(resp.content.strip()) / 10.0
    except ValueError:
        return 0.0

def rerank_images(query: str, candidates: list[dict]) -> list[dict]:
    for c in candidates:
        if c["type"] == "image":
            c["rerank_score"] = score_image_relevance(query, c["path"])
    return sorted(candidates, key=lambda x: x.get("rerank_score", x["score"]), reverse=True)

# Evaluation set: list of (query_text, [relevant_image_paths])
eval_pairs = [
    ("quarterly revenue bar chart", ["images/page12_chart.png"]),
    ("org chart showing engineering team", ["images/page5_orgchart.png"]),
    ("product roadmap timeline", ["images/page8_roadmap.png"]),
]

def recall_at_k(
    eval_pairs: list[tuple],
    search_fn,
    k: int = 5,
) -> float:
    hits = 0
    for query, relevant in eval_pairs:
        results = search_fn(query, k=k)
        retrieved_paths = {r["path"] for r in results if r["type"] == "image"}
        if any(p in retrieved_paths for p in relevant):
            hits += 1
    return hits / len(eval_pairs)

r5 = recall_at_k(eval_pairs, lambda q, k: idx.search(q, k=k), k=5)
print(f"R@5: {r5:.2%}")

def mrr(
    eval_pairs: list[tuple],
    search_fn,
    k: int = 10,
) -> float:
    rr_sum = 0.0
    for query, relevant in eval_pairs:
        results = search_fn(query, k=k)
        for rank, r in enumerate(results, start=1):
            if r.get("type") == "image" and r["path"] in relevant:
                rr_sum += 1.0 / rank
                break
    return rr_sum / len(eval_pairs)

