import torch
import numpy as np

def maxsim_score(
    query_token_vecs: np.ndarray,   # (n_query_tokens, dim)
    patch_vecs: np.ndarray,          # (n_patches, dim)
) -> float:
    """Sum of per-query-token maximum cosine similarity over patches."""
    # Both sets should be L2-normalised
    scores = query_token_vecs @ patch_vecs.T  # (n_tokens, n_patches)
    return float(scores.max(axis=1).sum())    # sum of per-token maxima

# For a set of candidate pages:
def rank_pages_by_maxsim(
    query_token_vecs: np.ndarray,       # (n_tokens, dim)
    page_patch_vecs: list[np.ndarray],  # list of (1024, dim) arrays, one per page
) -> list[tuple[int, float]]:
    scored = [
        (i, maxsim_score(query_token_vecs, patches))
        for i, patches in enumerate(page_patch_vecs)
    ]
    return sorted(scored, key=lambda x: x[1], reverse=True)
